import React, { createContext, useState, useContext } from 'react';

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
  const [isDarkTheme, setIsDarkTheme] = useState(true);
  
  const theme = {
    background: isDarkTheme ? '#0A0A0A' : '#ffffff',
    text: isDarkTheme ? '#ffffff' : '#0A0A0A',
    primary: isDarkTheme ? '#FF0000' : '#FF0000',
    secondary: isDarkTheme ? '#1A1A1A' : '#f5f5f5',
    accent: isDarkTheme ? '#FF3333' : '#CC0000',
    navBackground: isDarkTheme ? 'rgba(10, 10, 10, 0.95)' : 'rgba(255, 255, 255, 0.95)',
    cardBackground: isDarkTheme ? 'rgba(26, 26, 26, 0.95)' : 'rgba(245, 245, 245, 0.95)',
    cardBorder: isDarkTheme ? 'rgba(255, 0, 0, 0.2)' : 'rgba(204, 0, 0, 0.2)',
    shadow: isDarkTheme ? '0 4px 20px rgba(255, 0, 0, 0.15)' : '0 4px 20px rgba(204, 0, 0, 0.15)',
    hoverColor: isDarkTheme ? '#FF3333' : '#CC0000',
    gradientPrimary: isDarkTheme 
      ? 'linear-gradient(120deg, rgba(10, 10, 10, 0.95), rgba(26, 26, 26, 0.95))'
      : 'linear-gradient(120deg, rgba(255, 255, 255, 0.95), rgba(245, 245, 245, 0.95))',
    gradientAccent: isDarkTheme
      ? 'linear-gradient(45deg, #FF0000, #FF3333)'
      : 'linear-gradient(45deg, #CC0000, #FF0000)',
  };

  const toggleTheme = () => {
    setIsDarkTheme(!isDarkTheme);
  };

  return (
    <ThemeContext.Provider value={{ theme, isDarkTheme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};
